// tests/integration_test.rs
// This file is a separate crate, it uses your library like any user would

use my_library::{Config, process_data};

#[test]
fn test_full_pipeline() {
    let config = Config::default();
    let input = "hello world foo bar";
    let result = process_data(input, &config);

    assert!(result.is_ok());
    let output = result.unwrap();
    assert_eq!(output.word_count, 4);
    assert!(output.processing_time.as_millis() < 100);
}

#[test]
fn test_empty_input() {
    let config = Config::default();
    let result = process_data("", &config);
    assert!(result.is_ok());
    assert_eq!(result.unwrap().word_count, 0);
}

