// tests/db_tests.rs
struct TestContext {
    data_dir: tempfile::TempDir,
}

impl TestContext {
    fn new() -> Self {
        let data_dir = tempfile::TempDir::new().unwrap();
        // Setup: create test files, initialize state
        std::fs::write(
            data_dir.path().join("test.txt"),
            "test data"
        ).unwrap();
        TestContext { data_dir }
    }

    fn data_path(&self) -> &std::path::Path {
        self.data_dir.path()
    }
}

impl Drop for TestContext {
    fn drop(&mut self) {
        // Teardown: TempDir auto-cleans, but you can add more cleanup
        println!("Test cleanup complete");
    }
}

#[test]
fn test_with_context() {
    let ctx = TestContext::new();
    let path = ctx.data_path().join("test.txt");
    let content = std::fs::read_to_string(path).unwrap();
    assert_eq!(content, "test data");
} // ctx dropped here, cleanup runs
